     9→import com.grl.component.schema.RestrictionInfo;
    10→import com.grl.component.schema.SchemaVisitor;
    11→import com.grl.component.schema.TaxonomyInfo;
    12→import com.grl.component.schema.TaxonomyPattern;
    13→import io.swagger.v3.oas.models.SpecVersion;
    14→import io.swagger.v3.oas.models.media.ObjectSchema;
    15→import io.swagger.v3.oas.models.media.Schema;
    16→import java.util.ArrayList;
    17→import java.util.Collection;
    18→import java.util.HashSet;
    19→import java.util.LinkedHashSet;
    20→import java.util.List;
    21→import java.util.Map;
    22→import java.util.Optional;
    23→import java.util.Set;
    24→import java.util.function.Predicate;
    25→import java.util.logging.Logger;
    26→import java.util.stream.Collectors;
    27→import java.util.stream.Stream;
    28→import javax.annotation.Nullable;
    29→import org.apache.commons.lang3.StringUtils;
