    34→import org.semanticweb.owlapi.model.OWLDataProperty;
    35→import org.semanticweb.owlapi.model.OWLDataRestriction;
    36→import org.semanticweb.owlapi.model.OWLDatatype;
    37→import org.semanticweb.owlapi.model.OWLEntity;
