    46→/**
    47→ * Visitor interface to inspect OWL Class Restrictions.
    48→ *
    49→ * <p>This visitor traverses an OWL class hierarchy and collects type-safe restriction information
    50→ * for both object properties and data properties. It implements the Visitor pattern via
    51→ * {@link OWLObjectVisitor} to handle different types of OWL class expressions.
    52→ *
    53→ * <h2>Usage</h2>
    54→ * <pre>{@code
    55→ * OWLClass myClass = ...;
    56→ * OWLOntology ontology = ...;
    57→ * OWLClass owlThing = dataFactory.getOWLThing();
    58→ *
    59→ * SchemaVisitor visitor = new SchemaVisitor(myClass, ontology, owlThing);
    60→ * myClass.accept(visitor);
    61→ *
    62→ * // Access collected restrictions
    63→ * Map<String, List<RestrictionInfo>> restrictions = visitor.getRestrictions();
    64→ * Set<String> objectProperties = visitor.getObjectPropertyNames();
    65→ * }</pre>
    66→ *
    67→ * <h2>Constructor Parameters</h2>
    68→ * <ul>
    69→ *   <li><b>visitedClass</b>: The OWL class to analyze for restrictions</li>
    70→ *   <li><b>onto</b>: The ontology containing the class and its axioms</li>
    71→ *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
    72→ * </ul>
    73→ *
    74→ * <h2>Visitor Traversal Behavior</h2>
    75→ * <p>The visitor recursively processes class hierarchies:
    76→ * <ul>
    77→ *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
    78→ *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
    79→ *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
    80→ *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
    81→ * </ul>
    82→ *
    83→ * <h2>Thread Safety</h2>
    84→ * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
    85→ * traversal and should not be shared between threads or reused for multiple traversals.
    86→ *
    87→ * @see RestrictionInfo
    88→ * @see PropertyNameResolver
    89→ */
    90→public class SchemaVisitor implements OWLObjectVisitor {
    91→
    92→  private static final Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
    93→
    94→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    95→  private final TaxonomyPatternDetector taxonomyDetector;
    96→  private final Set<OWLClass> processedClasses;
    97→  private final OWLClass cls;
    98→  private final OWLOntology onto;
    99→  private final OWLClass owlThing;
   100→  private String propertyName;
   101→
   102→
   103→  // Type-safe storage (private with unmodifiable getters)
   104→  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   105→  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
   106→  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();
   107→
   108→  // Property name tracking (minimal - just names, not full OWL objects)
   109→  private final Set<String> objectPropertyNames = new HashSet<>();
   110→  private final Set<String> dataPropertyNames = new HashSet<>();
   111→
   112→  // Taxonomy pattern tracking
   113→  private final Map<String, TaxonomyInfo> taxonomyPatterns = new HashMap<>();
   114→
   115→  /**
   116→   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   117→   *
   118→   * @param visitedClass the OWL class to analyze for restrictions
   119→   * @param onto         the ontology containing the class and its axioms
   120→   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   121→   *                     no information)
   122→   */
   123→  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing) {
   124→    processedClasses = new HashSet<>();
   125→    this.cls = visitedClass;
   126→    this.onto = onto;
   127→    this.propertyName = "";
   128→    this.owlThing = owlThing;
   129→    this.taxonomyDetector = new TaxonomyPatternDetector(onto, nameResolver);
   130→  }
   131→
   132→  @Override
